package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void testParse_withValidInputStreamAndCharsetAndFormat() throws IOException {
        String csvContent = "header1,header2\nvalue1,value2\n";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            // Assertions.notNull calls are verified to be called with correct parameters
            assertionsMockedStatic.when(() -> Assertions.notNull(inputStream, "inputStream")).thenCallRealMethod();
            assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).thenCallRealMethod();

            // Mock parse(Reader, CSVFormat) to return a dummy CSVParser instance
            try (MockedStatic<CSVParser> csvParserStatic = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {
                CSVParser dummyParser = mock(CSVParser.class);
                csvParserStatic.when(() -> CSVParser.parse(any(java.io.Reader.class), eq(format))).thenReturn(dummyParser);

                CSVParser result = CSVParser.parse(inputStream, StandardCharsets.UTF_8, format);

                assertSame(dummyParser, result);

                assertionsMockedStatic.verify(() -> Assertions.notNull(inputStream, "inputStream"));
                assertionsMockedStatic.verify(() -> Assertions.notNull(format, "format"));
                csvParserStatic.verify(() -> CSVParser.parse(any(java.io.Reader.class), eq(format)));
            }
        }
    }

    @Test
    void testParse_withNullInputStream_throwsException() {
        CSVFormat format = mock(CSVFormat.class);
        InputStream inputStream = null;

        IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
            CSVParser.parse(inputStream, StandardCharsets.UTF_8, format);
        });
        assertTrue(thrown.getMessage().contains("inputStream"));
    }

    @Test
    void testParse_withNullFormat_throwsException() {
        String csvContent = "a,b\n1,2\n";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        CSVFormat format = null;

        IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
            CSVParser.parse(inputStream, StandardCharsets.UTF_8, format);
        });
        assertTrue(thrown.getMessage().contains("format"));
    }
}
